PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl:  <http://www.w3.org/2002/07/owl#>

SELECT ?comp ?label ?comment WHERE {
  ?comp a owl:Class .
  OPTIONAL { ?comp rdfs:label ?label }
  OPTIONAL { ?comp rdfs:comment ?comment }
  FILTER( CONTAINS(LCASE(STR(?label)), "critical") ||
          CONTAINS(LCASE(STR(?comment)), "critical raw material") ||
          CONTAINS(LCASE(STR(?comment)), "crit") )
}
LIMIT 50

